BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?type ?name WHERE {
  VALUES ?needle { "APS%20Operational%20Blackbox%20Specification%20JPL" "APS%20Black%20Box%20Specification%20TMT" }
  ?elem vocab:NamedElement_name ?name .
  FILTER(STR(?name) IN ("APS Operational Blackbox Specification JPL","APS Black Box Specification TMT"))
  OPTIONAL { ?elem rdf:type ?type }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?type ?name WHERE {
  VALUES ?pat { "Black%20Box%20Specification%20JPL" "APS%20Black%20Box%20Specification%20TMT" "APS%20Operational%20Blackbox%20Specification%20JPL" "Black%20Box%20Specification%20TMT" }
  ?elem vocab:NamedElement_name ?name .
  FILTER( CONTAINS(LCASE(STR(?name)), LCASE(STR(REPLACE(?pat,"%20"," ")))) )
  ?elem rdf:type ?type .
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?block ?blockName ?owned ?ownedType ?ownedName WHERE {
  VALUES ?block { 
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS::Black%2520Box%2520Specification::Structure::APS%2520Operational%2520Blackbox%2520Specification%2520JPL>
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Project%2520Systems%2520Engineering::01%2520Components::Operational::TMT%2520Observatory%2520System::Black%2520Box%2520Specifications%2520for%2520Suppliers::APS%2520Black%2520Box%2520Specification%2520TMT>
  }
  ?block vocab:NamedElement_name ?blockName .
  OPTIONAL { ?block vocab:Element_ownedElement+ ?owned . }
  OPTIONAL { ?owned rdf:type ?ownedType . }
  OPTIONAL { ?owned vocab:NamedElement_name ?ownedName . }
  FILTER(BOUND(?owned))
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?whichBlock ?blockName ?owned ?ownedType ?ownedName WHERE {
  {
    BIND("JPL" AS ?whichBlock)
    BIND(<http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS::Black%2520Box%2520Specification::Structure::APS%2520Operational%2520Blackbox%2520Specification%2520JPL> AS ?block)
  }
  UNION
  {
    BIND("TMT" AS ?whichBlock)
    BIND(<http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Project%2520Systems%2520Engineering::01%2520Components::Operational::TMT%2520Observatory%2520System::Black%2520Box%2520Specifications%2520for%2520Suppliers::APS%2520Black%2520Box%2520Specification%2520TMT> AS ?block)
  }
  ?block vocab:NamedElement_name ?blockName .
  OPTIONAL { ?block vocab:Element_ownedElement+ ?owned . }
  OPTIONAL { ?owned rdf:type ?ownedType . }
  OPTIONAL { ?owned vocab:NamedElement_name ?ownedName . }
  FILTER(BOUND(?owned))
}
ORDER BY ?whichBlock
LIMIT 25

